<?php require_once "../config/database.php"; require_once "../includes/session.php"; requireAdmin(); 
if(isset($_POST['add_product']))$conn->prepare("INSERT INTO products(product_name,description,price,stock,image_url) VALUES(?,?,?,?,?)")->execute([$_POST['product_name'],$_POST['description'],$_POST['price'],$_POST['stock'],$_POST['image_url']]);if(isset($_GET['delete']))$conn->prepare("DELETE FROM products WHERE product_id=?")->execute([$_GET['delete']]);include "../includes/header.php";$rows=$conn->query("SELECT * FROM products ORDER BY product_id DESC")->fetchAll(PDO::FETCH_ASSOC);?><div class="container"><h1 class="section-title">Products</h1><div class="form-card"><form method="POST"><input name="product_name" placeholder="Product"><textarea name="description" placeholder="Description"></textarea><input type="number" step="0.01" name="price" placeholder="Price"><input type="number" name="stock" placeholder="Stock"><input name="image_url" placeholder="Image URL"><button name="add_product" class="btn">Add Product</button></form></div><div class="table-wrap"><table><tr><th>Product</th><th>Price</th><th>Stock</th><th>Action</th></tr><?php foreach($rows as $p):?><tr><td><?=e($p['product_name'])?></td><td>₱<?=number_format($p['price'],2)?></td><td><?=$p['stock']?></td><td><a onclick="return confirmDelete()" class="btn danger" href="?delete=<?=$p['product_id']?>">Delete</a></td></tr><?php endforeach;?></table></div></div><?php include "../includes/footer.php";?>
